{
  "name": "ProActive Timer & Reminder",
  "description": "A productivity assistant that proactively pushes you to stay active, manages tasks with smart reminders, and features a color-coded focus timer.",
  "requestFramePermissions": []
}

export enum TimerMode {
  FOCUS = 'FOCUS',
  PHYSICAL = 'PHYSICAL',
  BREAK = 'BREAK'
}

export interface Task {
  id: string;
  title: string;
  category: string;
  reminderTime: string;
  isCompleted: boolean;
  createdAt: number;
}

export interface ProductivityHours {
  start: string; // HH:mm
  end: string;   // HH:mm
}

export interface AppState {
  tasks: Task[];
  productivityHours: ProductivityHours;
  lastNudgeTime: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getNudgeMessage = async (tasks: string[], productivityHours: { start: string; end: string }) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User is in their productivity hours (${productivityHours.start} - ${productivityHours.end}). 
      Current pending tasks: ${tasks.join(', ') || 'None'}.
      Act as a proactive, slightly pushy but highly motivational assistant. 
      Generate a short, punchy, energetic reminder in Indonesian to start working or exercising. 
      Limit to 2 sentences. Include emojis.`,
      config: {
        temperature: 0.9,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Ayo! Jangan nunda lagi, waktunya produktif! 🔥";
  }
};

export const getTaskRecommendation = async (task: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Task: "${task}". 
      Recommend a good time (morning, afternoon, evening) and a brief motivational tip in Indonesian for this specific task. 
      Response should be short.`,
      config: {
        temperature: 0.7,
      }
    });
    return response.text;
  } catch (error) {
    return "Waktu terbaik adalah SEKARANG! Semangat!";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerMode } from '../types';

interface TimerProps {
  onComplete: (mode: TimerMode) => void;
}

const MODE_CONFIG = {
  [TimerMode.FOCUS]: {
    color: 'bg-orange-600',
    ring: 'text-orange-500',
    label: 'Focus Time (Study/Work)',
    defaultTime: 25 * 60,
  },
  [TimerMode.PHYSICAL]: {
    color: 'bg-blue-600',
    ring: 'text-blue-500',
    label: 'Body Movement (Exercise)',
    defaultTime: 15 * 60,
  },
  [TimerMode.BREAK]: {
    color: 'bg-emerald-600',
    ring: 'text-emerald-500',
    label: 'Refreshing Break',
    defaultTime: 5 * 60,
  }
};

export const TimerComponent: React.FC<TimerProps> = ({ onComplete }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(MODE_CONFIG[TimerMode.FOCUS].defaultTime);
  const [isActive, setIsActive] = useState(false);
  const intervalRef = useRef<number | null>(null);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleModeChange = (newMode: TimerMode) => {
    setMode(newMode);
    setTimeLeft(MODE_CONFIG[newMode].defaultTime);
    setIsActive(false);
  };

  const toggleTimer = () => {
    setIsActive(!isActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(MODE_CONFIG[mode].defaultTime);
  };

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      onComplete(mode);
      if (intervalRef.current) clearInterval(intervalRef.current);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isActive, timeLeft, mode, onComplete]);

  const progress = (timeLeft / MODE_CONFIG[mode].defaultTime) * 100;

  return (
    <div className="flex flex-col items-center p-8 glass rounded-3xl shadow-2xl transition-all duration-500">
      <div className="flex gap-2 mb-8 bg-slate-800/50 p-2 rounded-2xl">
        {Object.values(TimerMode).map((m) => (
          <button
            key={m}
            onClick={() => handleModeChange(m)}
            className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-wider transition-all ${
              mode === m 
                ? `${MODE_CONFIG[m].color} text-white shadow-lg` 
                : 'text-slate-400 hover:text-white'
            }`}
          >
            {m}
          </button>
        ))}
      </div>

      <div className="relative w-64 h-64 flex items-center justify-center">
        <svg className="w-full h-full transform -rotate-90">
          <circle
            cx="128"
            cy="128"
            r="120"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            className="text-slate-800"
          />
          <circle
            cx="128"
            cy="128"
            r="120"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={754}
            strokeDashoffset={754 - (754 * progress) / 100}
            strokeLinecap="round"
            className={`${MODE_CONFIG[mode].ring} transition-all duration-500 ease-linear`}
          />
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-6xl font-black tracking-tighter tabular-nums">
            {formatTime(timeLeft)}
          </span>
          <p className="text-sm font-medium opacity-60 mt-2">{MODE_CONFIG[mode].label}</p>
        </div>
      </div>

      <div className="flex gap-4 mt-10">
        <button
          onClick={toggleTimer}
          className={`w-40 py-4 rounded-2xl font-bold text-lg transition-all active:scale-95 ${
            isActive 
              ? 'bg-slate-700 hover:bg-slate-600 text-white' 
              : `${MODE_CONFIG[mode].color} hover:opacity-90 shadow-xl shadow-${mode === TimerMode.PHYSICAL ? 'blue' : mode === TimerMode.BREAK ? 'emerald' : 'orange'}-900/40 text-white`
          }`}
        >
          {isActive ? 'PAUSE' : 'START'}
        </button>
        <button
          onClick={resetTimer}
          className="px-6 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all active:scale-95"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
          </svg>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Task } from '../types';
import { getTaskRecommendation } from '../services/geminiService';

interface TaskListProps {
  tasks: Task[];
  onAddTask: (task: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => void;
  onToggleTask: (id: string) => void;
  onDeleteTask: (id: string) => void;
}

export const TaskList: React.FC<TaskListProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
  const [title, setTitle] = useState('');
  const [time, setTime] = useState('');
  const [category, setCategory] = useState('Productivity');
  const [isAdding, setIsAdding] = useState(false);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [advice, setAdvice] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    setLoadingAdvice(true);
    const rec = await getTaskRecommendation(title);
    setAdvice(rec);
    setLoadingAdvice(false);

    onAddTask({ title, reminderTime: time, category });
    setTitle('');
    setTime('');
    setIsAdding(false);

    setTimeout(() => setAdvice(null), 5000);
  };

  return (
    <div className="w-full flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold">Your Missions</h2>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="p-2 bg-indigo-600 hover:bg-indigo-500 rounded-xl transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={isAdding ? "M18 12H6" : "M12 6v6m0 0v6m0-6h6m-6 0H6"} />
          </svg>
        </button>
      </div>

      {advice && (
        <div className="p-4 bg-indigo-900/40 border border-indigo-500/30 rounded-2xl text-sm italic animate-pulse">
          💡 Tips: {advice}
        </div>
      )}

      {isAdding && (
        <form onSubmit={handleSubmit} className="p-6 glass rounded-2xl flex flex-col gap-4 animate-in fade-in slide-in-from-top-4 duration-300">
          <input
            type="text"
            placeholder="What needs to be done?"
            className="bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none focus:border-indigo-500 transition-all"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <div className="flex gap-4">
            <div className="flex-1">
              <label className="text-xs uppercase font-bold text-slate-500 block mb-1">When?</label>
              <input
                type="time"
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none"
                value={time}
                onChange={(e) => setTime(e.target.value)}
              />
            </div>
            <div className="flex-1">
              <label className="text-xs uppercase font-bold text-slate-500 block mb-1">Tag</label>
              <select 
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
              >
                <option>Productivity</option>
                <option>Exercise</option>
                <option>Learning</option>
                <option>Housework</option>
              </select>
            </div>
          </div>
          <button 
            type="submit" 
            disabled={loadingAdvice}
            className="bg-indigo-600 py-3 rounded-xl font-bold text-white hover:bg-indigo-500 transition-all disabled:opacity-50"
          >
            {loadingAdvice ? 'Optimizing...' : 'DEPLOY TASK'}
          </button>
        </form>
      )}

      <div className="flex flex-col gap-3">
        {tasks.length === 0 ? (
          <div className="py-12 text-center text-slate-500 italic">No active missions. Let's start something!</div>
        ) : (
          tasks.map(task => (
            <div 
              key={task.id} 
              className={`group flex items-center justify-between p-4 glass rounded-2xl transition-all hover:translate-x-1 ${task.isCompleted ? 'opacity-50 grayscale' : 'border-l-4 border-l-indigo-500'}`}
            >
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => onToggleTask(task.id)}
                  className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${task.isCompleted ? 'bg-indigo-500 border-indigo-500' : 'border-slate-600 group-hover:border-indigo-500'}`}
                >
                  {task.isCompleted && (
                    <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                    </svg>
                  )}
                </button>
                <div>
                  <h4 className={`font-semibold ${task.isCompleted ? 'line-through' : ''}`}>{task.title}</h4>
                  <div className="flex gap-2 items-center mt-1">
                    <span className="text-[10px] uppercase font-bold px-2 py-0.5 bg-slate-800 rounded text-slate-400">{task.category}</span>
                    {task.reminderTime && (
                      <span className="text-xs text-indigo-400 font-medium">⏰ {task.reminderTime}</span>
                    )}
                  </div>
                </div>
              </div>
              <button 
                onClick={() => onDeleteTask(task.id)}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-500 hover:text-red-500 transition-all"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    const messages = {
      [TimerMode.FOCUS]: "Sesi fokus selesai! Keren banget. Sekarang waktunya istirahat sebentar ya? 🍵",
      [TimerMode.PHYSICAL]: "Olahraga selesai! Tubuhmu pasti berterima kasih. Minum air dulu yuk! 💧",
      [TimerMode.BREAK]: "Istirahat cukup. Siap untuk kembali beraksi? Let's go! 🚀"
    };
    setNudge(messages[mode]);
    setTimeout(() => setNudge(null), 10000);
  }, []);

  // Proactive Nudging Logic
  useEffect(() => {
    const checkProductivity = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      // Check if within hours
      if (currentTimeStr >= start && currentTimeStr <= end) {
        // Only nudge once every 2 hours if no timer is running (we don't have global timer state here, but we can nudge if active)
        const timeSinceLastNudge = Date.now() - state.lastNudgeTime;
        if (timeSinceLastNudge > 2 * 60 * 60 * 1000) {
          const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
          const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours);
          setNudge(aiMessage || "Ayo produktif!");
          setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
        }
      }
    };

    const interval = setInterval(checkProductivity, 60000 * 30); // Check every 30 mins
    return () => clearInterval(interval);
  }, [state.productivityHours, state.tasks, state.lastNudgeTime]);

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="p-6 sticky top-0 z-50 glass">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
              PROACTIVE.
            </h1>
            <p className="text-[10px] uppercase tracking-widest font-bold text-slate-500">Timer & Reminder Assistant</p>
          </div>
          <button 
            onClick={() => setShowSettings(!showSettings)}
            className="p-3 bg-slate-800 hover:bg-slate-700 rounded-full transition-all"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 mt-8 space-y-12">
        {/* Proactive Notification Area */}
        {nudge && (
          <div className="bg-indigo-600 shadow-xl shadow-indigo-900/40 p-5 rounded-3xl flex items-start gap-4 animate-bounce-short">
            <div className="bg-white/20 p-2 rounded-xl">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <div className="flex-1">
              <h5 className="font-bold text-white text-sm">PROACTIVE NUDGE</h5>
              <p className="text-indigo-100 text-sm">{nudge}</p>
            </div>
            <button onClick={() => setNudge(null)} className="text-white/60 hover:text-white">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}

        {/* Settings Modal/View */}
        {showSettings && (
          <div className="glass p-8 rounded-3xl space-y-6">
            <h3 className="text-xl font-bold">Productivity Setup</h3>
            <div className="flex flex-wrap gap-6">
              <div className="flex-1 min-w-[200px]">
                <label className="text-xs font-bold text-slate-500 uppercase block mb-2">Shift Start</label>
                <input 
                  type="time" 
                  value={state.productivityHours.start}
                  onChange={(e) => updateHours({ ...state.productivityHours, start: e.target.value })}
                  className="w-full bg-slate-900 p-3 rounded-xl border border-slate-700 outline-none" 
                />
              </div>
              <div className="flex-1 min-w-[200px]">
                <label className="text-xs font-bold text-slate-500 uppercase block mb-2">Shift End</label>
                <input 
                  type="time" 
                  value={state.productivityHours.end}
                  onChange={(e) => updateHours({ ...state.productivityHours, end: e.target.value })}
                  className="w-full bg-slate-900 p-3 rounded-xl border border-slate-700 outline-none" 
                />
              </div>
            </div>
            <p className="text-xs text-slate-400">
              I will proactively nudge you to stay active between these hours if I notice you're idling!
            </p>
            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-slate-800 py-3 rounded-xl font-bold"
            >
              SAVE SETTINGS
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start">
          {/* Left: Timer */}
          <div className="sticky top-28 space-y-6">
            <TimerComponent onComplete={handleTimerComplete} />
            <div className="p-6 glass rounded-3xl">
              <h4 className="font-bold text-sm text-slate-400 mb-2 uppercase tracking-tight">Today's Focus Meter</h4>
              <div className="w-full h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-500 transition-all duration-1000" 
                  style={{ width: `${Math.min((state.tasks.filter(t => t.isCompleted).length / (state.tasks.length || 1)) * 100, 100)}%` }}
                ></div>
              </div>
              <p className="text-[10px] mt-2 text-slate-500 font-medium">
                {state.tasks.filter(t => t.isCompleted).length} of {state.tasks.length} tasks completed today
              </p>
            </div>
          </div>

          {/* Right: Tasks */}
          <TaskList 
            tasks={state.tasks} 
            onAddTask={addTask} 
            onToggleTask={toggleTask} 
            onDeleteTask={deleteTask} 
          />
        </div>
      </main>

      <style>{`
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-short {
          animation: bounce-short 2s infinite;
        }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getNudgeMessage = async (tasks: string[], productivityHours: { start: string; end: string }, isIdle: boolean) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User is currently in their productivity hours (${productivityHours.start} - ${productivityHours.end}). 
      Pending tasks: ${tasks.join(', ') || 'Nothing listed yet'}.
      Status: ${isIdle ? 'User is IDLE (not using timer, no recent tasks done)' : 'User is active but needs a push'}.

      Act as a "ProActive Timer" assistant. Your personality is "cerewet" (nagging/talkative) but high-energy and motivational in Indonesian.
      Don't let them be lazy! 

      If idle: Strongly push them to start moving or working. Remind them it's their set productivity time.
      If not idle: Praise them but keep the momentum high.

      Limit to 2-3 sentences. Use emojis like 🔥, 🚀, 💪.`,
      config: {
        temperature: 1.0, // Higher temperature for more varied nagging
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Woi! Ini jam produktif kamu! Ayo gerak, jangan cuma liatin layar. Mulai tugas atau olahraga sekarang! 🔥";
  }
};

