import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [idleStartTime, setIdleStartTime] = useState<number>(Date.now());
  const [showIdleWarning, setShowIdleWarning] = useState(false);
  const [isWarningDismissed, setIsWarningDismissed] = useState(false);
  const [isNudging, setIsNudging] = useState(false);

  const idleCheckInterval = useRef<number | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Reset idle timer whenever user is "active"
  const recordActivity = useCallback(() => {
    const wasIdle = Date.now() - idleStartTime > 15 * 60 * 1000;
    setIdleStartTime(Date.now());
    setShowIdleWarning(false);
    // If they were in an idle state and now active, reset dismissal so it can trigger next time they go idle
    if (wasIdle || isWarningDismissed) {
      setIsWarningDismissed(false);
    }
  }, [idleStartTime, isWarningDismissed]);

  const triggerManualNudge = async () => {
    recordActivity();
    setIsNudging(true);
    const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
    const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, false);
    setNudge(aiMessage || "Semangat! Kamu pasti bisa menyelesaikan semua misi hari ini! 💪");
    setIsNudging(false);
    setTimeout(() => setNudge(null), 10000);
  };

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    recordActivity();
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    recordActivity();
    const messages = {
      [TimerMode.FOCUS]: "Woi! Sesi fokus kelar. Istirahat 5 menit, jangan keterusan scrolling! 🍵",
      [TimerMode.PHYSICAL]: "Olahraga mantap! Keringetan itu sehat. Rehat dikit terus balik lagi! 💪",
      [TimerMode.BREAK]: "Udah cukup santainya! Balik kerja sekarang, tugasmu nungguin! 🚀"
    };
    setNudge(messages[mode]);
    setTimeout(() => setNudge(null), 10000);
  }, [recordActivity]);

  const handleTimerStatus = (active: boolean) => {
    setIsTimerActive(active);
    if (active) recordActivity();
  };

  // Idle and Proactive Nudging Logic
  useEffect(() => {
    const checkStatus = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      const isWithinHours = currentTimeStr >= start && currentTimeStr <= end;

      if (isWithinHours) {
        if (!isTimerActive) {
          const currentTimeMs = Date.now();
          const idleDuration = currentTimeMs - idleStartTime;

          // 1. Prominent Idle Warning after 15 minutes of inactivity
          if (idleDuration > 15 * 60 * 1000 && !isWarningDismissed) {
            setShowIdleWarning(true);
          }

          // 2. AI-based Nudge every 30 minutes
          const timeSinceLastNudge = currentTimeMs - state.lastNudgeTime;
          if (timeSinceLastNudge > 30 * 60 * 1000) { 
            const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
            const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, true);
            setNudge(aiMessage || "Ini jam produktifmu! Ayo mulai bergerak!");
            setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
          }
        } else {
          setShowIdleWarning(false);
        }
      } else {
        setShowIdleWarning(false);
      }
    };

    // Check every minute
    idleCheckInterval.current = window.setInterval(checkStatus, 60 * 1000);
    return () => {
      if (idleCheckInterval.current) clearInterval(idleCheckInterval.current);
