              <p className="text-sm text-slate-300">
                ⚠️ <span className="font-bold text-white">Attention:</span> Saya akan cerewet jika kamu diam saja selama 15 menit di jam ini.
              </p>
            </div>
            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-indigo-600 hover:bg-indigo-500 py-4 rounded-2xl font-black text-white shadow-lg shadow-indigo-900/40 transition-all"
            >
              SAVE SETTINGS
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start mt-4">
          {/* Left: Timer */}
          <div className="lg:sticky lg:top-28 space-y-6">
            <TimerComponent onComplete={handleTimerComplete} onStatusChange={handleTimerStatus} />
            <div className="p-6 glass rounded-3xl border border-white/5">
              <div className="flex justify-between items-end mb-4">
                <div>
                  <h4 className="font-bold text-sm text-slate-400 uppercase tracking-tight">Mission Progress</h4>
                  <p className="text-2xl font-black">
                    {state.tasks.length > 0 ? Math.round((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100) : 0}%
                  </p>
                </div>
                <p className="text-[10px] text-slate-500 font-bold mb-1">
                  {state.tasks.filter(t => t.isCompleted).length} / {state.tasks.length} DONE
                </p>
              </div>
              <div className="w-full h-3 bg-slate-800 rounded-full overflow-hidden p-0.5">
                <div 
                  className="h-full bg-gradient-to-r from-indigo-500 to-cyan-400 rounded-full transition-all duration-1000 shadow-[0_0_10px_rgba(99,102,241,0.5)]" 
                  style={{ width: `${state.tasks.length > 0 ? Math.min((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100, 100) : 0}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* Right: Tasks */}
          <div onClick={(e) => e.stopPropagation()}>
            <TaskList 
              tasks={state.tasks} 
              onAddTask={addTask} 
              onToggleTask={toggleTask} 
              onDeleteTask={deleteTask} 
            />
          </div>
        </div>
      </main>

      {/* Global CSS for Animations */}
      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-3px); }
        }
        @keyframes pulse-intense {
          0% { transform: scale(1); background-color: rgba(220, 38, 38, 0.4); }
          50% { transform: scale(1.15); background-color: rgba(249, 115, 22, 0.6); }
          100% { transform: scale(1); background-color: rgba(220, 38, 38, 0.4); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-2px); }
          20%, 40%, 60%, 80% { transform: translateX(2px); }
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 1.5s ease-in-out infinite;
        }
        .animate-pulse-intense {
          animation: pulse-intense 1s ease-in-out infinite;
        }
        .animate-shake {
          animation: shake 0.5s cubic-bezier(.36,.07,.19,.97) both;
          animation-iteration-count: 2;
        }
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

export default App;

export enum TimerMode {
  FOCUS = 'FOCUS',
  PHYSICAL = 'PHYSICAL',
  BREAK = 'BREAK'
}

export interface Task {
  id: string;
  title: string;
  category: string;
  reminderTime: string;
  dueDate: string; // YYYY-MM-DD
  isCompleted: boolean;
  createdAt: number;
}

export interface ProductivityHours {
  start: string; // HH:mm
  end: string;   // HH:mm
}

export interface AppState {
  tasks: Task[];
  productivityHours: ProductivityHours;
  lastNudgeTime: number;
}

import React, { useState } from 'react';
import { Task } from '../types';
import { getTaskRecommendation } from '../services/geminiService';

interface TaskListProps {
  tasks: Task[];
  onAddTask: (task: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => void;
  onToggleTask: (id: string) => void;
  onDeleteTask: (id: string) => void;
}

export const TaskList: React.FC<TaskListProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
  const [title, setTitle] = useState('');
  const [time, setTime] = useState('');
  const [dueDate, setDueDate] = useState(new Date().toISOString().split('T')[0]);
  const [category, setCategory] = useState('Productivity');
  const [isAdding, setIsAdding] = useState(false);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [advice, setAdvice] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    setLoadingAdvice(true);
    const rec = await getTaskRecommendation(title);
    setAdvice(rec);
    setLoadingAdvice(false);

    onAddTask({ title, reminderTime: time, category, dueDate });
    setTitle('');
    setTime('');
    setIsAdding(false);

    setTimeout(() => setAdvice(null), 8000);
  };

  return (
    <div className="w-full flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold">Misi Utama</h2>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="p-3 bg-indigo-600 hover:bg-indigo-500 rounded-2xl transition-all shadow-lg shadow-indigo-900/40"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={isAdding ? "M18 12H6" : "M12 6v6m0 0v6m0-6h6m-6 0H6"} />
          </svg>
        </button>
      </div>

      {advice && (
        <div className="p-4 bg-indigo-900/40 border border-indigo-500/30 rounded-2xl text-sm italic animate-in fade-in zoom-in">
          💡 <span className="font-bold text-indigo-300">Strategy:</span> {advice}
        </div>
      )}

      {isAdding && (
        <form onSubmit={handleSubmit} className="p-6 glass rounded-2xl flex flex-col gap-4 animate-in fade-in slide-in-from-top-4 duration-300">
          <input
            type="text"
            placeholder="Apa yang harus diselesaikan?"
            className="bg-slate-900/50 border border-slate-700 rounded-xl p-4 outline-none focus:border-indigo-500 transition-all text-lg font-medium"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
             <div className="flex-1">
              <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Target Tanggal (Due Date)</label>
              <input
                type="date"
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none focus:border-indigo-500"
                value={dueDate}
                onChange={(e) => setDueDate(e.target.value)}
              />
            </div>
            <div className="flex-1">
              <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Jam Reminder (Opsional)</label>
              <input
                type="time"
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none focus:border-indigo-500"
                value={time}
                onChange={(e) => setTime(e.target.value)}
              />
            </div>
          </div>

          <div className="flex-1">
            <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Kategori</label>
            <select 
              className="w-full bg-slate-900/50 border border-slate-700 rounded-xl p-3 outline-none focus:border-indigo-500"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
            >
              <option>Productivity</option>
              <option>Exercise</option>
              <option>Learning</option>
              <option>Housework</option>
            </select>
          </div>

          <button 
            type="submit" 
            disabled={loadingAdvice}
            className="bg-indigo-600 py-4 rounded-xl font-bold text-white hover:bg-indigo-500 transition-all disabled:opacity-50 mt-2 shadow-lg"
          >
            {loadingAdvice ? 'MENGOPTIMALKAN...' : 'DEPLOY MISSION'}
          </button>
        </form>
      )}

      <div className="flex flex-col gap-3">
        {tasks.length === 0 ? (
          <div className="py-12 text-center text-slate-500 italic glass rounded-3xl">Belum ada misi. Tambahkan satu untuk memulai!</div>
        ) : (
          tasks.map(task => (
            <div 
              key={task.id} 
              className={`group flex items-center justify-between p-5 glass rounded-2xl transition-all hover:translate-x-1 ${task.isCompleted ? 'opacity-40 grayscale' : 'border-l-4 border-l-indigo-500'}`}
            >
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => onToggleTask(task.id)}
                  className={`w-7 h-7 rounded-lg border-2 flex items-center justify-center transition-all ${task.isCompleted ? 'bg-indigo-500 border-indigo-500' : 'border-slate-600 group-hover:border-indigo-500'}`}
                >
                  {task.isCompleted && (
                    <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                    </svg>
                  )}
                </button>
                <div>
                  <h4 className={`font-bold text-lg ${task.isCompleted ? 'line-through' : ''}`}>{task.title}</h4>
                  <div className="flex gap-3 items-center mt-1">
                    <span className="text-[9px] uppercase font-black px-2 py-0.5 bg-indigo-500/20 text-indigo-300 rounded">{task.category}</span>
                    <span className="text-[11px] text-slate-400 font-medium">📅 {task.dueDate}</span>
                    {task.reminderTime && (
                      <span className="text-[11px] text-orange-400 font-medium">⏰ {task.reminderTime}</span>
                    )}
                  </div>
                </div>
              </div>
              <button 
                onClick={() => onDeleteTask(task.id)}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-500 hover:text-red-500 transition-all"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Task } from '../types';

interface CalendarViewProps {
  tasks: Task[];
}

export const CalendarView: React.FC<CalendarViewProps> = ({ tasks }) => {
  const [viewDate, setViewDate] = useState(new Date());

  // Generate days for the current month
  const getDaysInMonth = (year: number, month: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const currentYear = viewDate.getFullYear();
  const currentMonth = viewDate.getMonth();
  const daysInMonth = getDaysInMonth(currentYear, currentMonth);
  const firstDayOfMonth = new Date(currentYear, currentMonth, 1).getDay();

  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const emptyDays = Array.from({ length: firstDayOfMonth }, (_, i) => i);

  const monthName = viewDate.toLocaleString('id-ID', { month: 'long' });

  const tasksByDate = tasks.reduce((acc, task) => {
    const date = task.dueDate;
    if (!acc[date]) acc[date] = [];
    acc[date].push(task);
    return acc;
  }, {} as Record<string, Task[]>);

  const changeMonth = (delta: number) => {
    const newDate = new Date(viewDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setViewDate(newDate);
  };

  const todayStr = new Date().toISOString().split('T')[0];

  return (
    <div className="glass p-6 rounded-3xl border border-white/5 space-y-4">
      <div className="flex items-center justify-between mb-2">
        <h3 className="font-black text-xl uppercase tracking-tighter">Mission Schedule</h3>
        <div className="flex gap-2">
          <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7"/></svg>
          </button>
          <span className="font-bold min-w-[120px] text-center">{monthName} {currentYear}</span>
          <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7"/></svg>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-1">
        {['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'].map(day => (
          <div key={day} className="text-center text-[10px] font-black text-slate-500 uppercase py-2">{day}</div>
        ))}
        {emptyDays.map(d => <div key={`empty-${d}`} className="aspect-square"></div>)}
        {days.map(day => {
          const dateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
          const dayTasks = tasksByDate[dateStr] || [];
          const hasIncomplete = dayTasks.some(t => !t.isCompleted);
          const isToday = dateStr === todayStr;

          return (
            <div 
              key={day} 
              className={`aspect-square relative flex flex-col items-center justify-center rounded-xl border border-white/5 transition-all hover:bg-white/5 group ${isToday ? 'bg-indigo-500/20 border-indigo-500/40' : ''}`}
            >
              <span className={`text-xs font-bold ${isToday ? 'text-indigo-400' : 'text-slate-400'}`}>{day}</span>
              {dayTasks.length > 0 && (
                <div className="flex gap-0.5 mt-1">
                  {dayTasks.slice(0, 3).map((t, i) => (
                    <div 
                      key={t.id} 
                      className={`w-1.5 h-1.5 rounded-full ${t.isCompleted ? 'bg-slate-600' : 'bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,0.5)] animate-pulse'}`}
                    />
                  ))}
                  {dayTasks.length > 3 && <div className="text-[8px] text-indigo-400 font-bold">+</div>}
                </div>
              )}
              {/* Tooltip on hover */}
              {dayTasks.length > 0 && (
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 p-2 bg-slate-900 border border-slate-700 rounded-lg shadow-2xl opacity-0 group-hover:opacity-100 pointer-events-none transition-opacity z-50 min-w-[120px]">
                   <p className="text-[10px] font-bold text-indigo-400 mb-1">{day} {monthName}</p>
                   {dayTasks.map(t => (
                     <p key={t.id} className="text-[9px] text-white truncate">• {t.title}</p>
                   ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { CalendarView } from './components/CalendarView';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [idleStartTime, setIdleStartTime] = useState<number>(Date.now());
  const [showIdleWarning, setShowIdleWarning] = useState(false);
  const [isWarningDismissed, setIsWarningDismissed] = useState(false);
  const [isNudging, setIsNudging] = useState(false);

  const idleCheckInterval = useRef<number | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Reset idle timer whenever user is "active"
  const recordActivity = useCallback(() => {
    const wasIdle = Date.now() - idleStartTime > 15 * 60 * 1000;
    setIdleStartTime(Date.now());
    setShowIdleWarning(false);
    // If they were in an idle state and now active, reset dismissal so it can trigger next time they go idle
    if (wasIdle || isWarningDismissed) {
      setIsWarningDismissed(false);
    }
  }, [idleStartTime, isWarningDismissed]);

  const triggerManualNudge = async () => {
    recordActivity();
    setIsNudging(true);
    const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
    const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, false);
    setNudge(aiMessage || "Semangat! Kamu pasti bisa menyelesaikan semua misi hari ini! 💪");
    setIsNudging(false);
    setTimeout(() => setNudge(null), 10000);
  };

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    recordActivity();
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    recordActivity();
    if (mode === TimerMode.BREAK) {
      setNudge("Istirahat selesai! 🍵 Baterai sudah full? Sekarang waktunya kembali ke mode serius. Selesaikan satu misi besarmu sekarang juga! 🚀🔥");
    } else {
      const messages = {
        [TimerMode.FOCUS]: "Woi! Sesi fokus kelar. Istirahat 5 menit, jangan keterusan scrolling! 🍵",
        [TimerMode.PHYSICAL]: "Olahraga mantap! Keringetan itu sehat. Rehat dikit terus balik lagi! 💪",
        [TimerMode.BREAK]: "" // Handled above
      };
      setNudge(messages[mode]);
    }
    setTimeout(() => setNudge(null), 15000);
  }, [recordActivity]);

  const handleTimerStatus = (active: boolean) => {
    setIsTimerActive(active);
    if (active) recordActivity();
  };

  // Idle and Proactive Nudging Logic
  useEffect(() => {
    const checkStatus = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      const isWithinHours = currentTimeStr >= start && currentTimeStr <= end;

      if (isWithinHours) {
        if (!isTimerActive) {
          const currentTimeMs = Date.now();
          const idleDuration = currentTimeMs - idleStartTime;

          // 1. Prominent Idle Warning after 15 minutes of inactivity
          if (idleDuration > 15 * 60 * 1000 && !isWarningDismissed) {
            setShowIdleWarning(true);
          }

          // 2. AI-based Nudge every 30 minutes
          const timeSinceLastNudge = currentTimeMs - state.lastNudgeTime;
          if (timeSinceLastNudge > 30 * 60 * 1000) { 
            const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
            const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, true);
            setNudge(aiMessage || "Ini jam produktifmu! Ayo mulai bergerak!");
            setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
          }
        } else {
          setShowIdleWarning(false);
        }
      } else {
        setShowIdleWarning(false);
      }
    };

    // Check every minute
    idleCheckInterval.current = window.setInterval(checkStatus, 60 * 1000);
    return () => {
      if (idleCheckInterval.current) clearInterval(idleCheckInterval.current);
    };
  }, [state.productivityHours, state.tasks, state.lastNudgeTime, isTimerActive, idleStartTime, isWarningDismissed]);

  return (
    <div className="min-h-screen pb-12 bg-[#0f172a] selection:bg-indigo-500/30" onClick={recordActivity}>
      {/* Header */}
      <header className="p-6 sticky top-0 z-50 glass">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-900/40">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
                PROACTIVE
              </h1>
              <p className="text-[9px] uppercase tracking-widest font-bold text-slate-500">Bossy Assistant</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:block text-right">
                <p className="text-[10px] text-slate-500 font-bold uppercase">Jam Produktif</p>
                <p className="text-xs font-semibold text-indigo-400">{state.productivityHours.start} - {state.productivityHours.end}</p>
             </div>
            <button 
              onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
              className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all group"
            >
              <svg className="w-5 h-5 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 mt-8 space-y-8">

        {/* Nudge Me Button - Proactive Seek of Motivation */}
        <div className="flex justify-center">
          <button 
            disabled={isNudging}
            onClick={(e) => { e.stopPropagation(); triggerManualNudge(); }}
            className={`flex items-center gap-3 px-10 py-5 bg-gradient-to-r from-indigo-500 to-indigo-700 hover:from-indigo-400 hover:to-indigo-600 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all active:scale-95 ${isNudging ? 'animate-pulse opacity-70' : 'hover:-translate-y-1'}`}
          >
            <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <span className="tracking-tight uppercase">{isNudging ? 'MENGHUBUNGI ASISTEN...' : 'NUDGE ME!'}</span>
          </button>
        </div>

        {/* Prominent Idle Warning Section */}
        {showIdleWarning && (
          <div className="relative overflow-hidden bg-red-600/20 border border-red-500/30 rounded-3xl p-8 shadow-2xl shadow-red-900/30 animate-in fade-in zoom-in duration-300 animate-shake">
            <div className="absolute top-0 right-0 p-4">
              <button 
                onClick={(e) => { 
                  e.stopPropagation(); 
                  setShowIdleWarning(false); 
                  setIsWarningDismissed(true); 
                }}
                className="text-red-400 hover:text-red-200 transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div className="flex flex-col sm:flex-row items-center gap-8">
              <div className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center animate-pulse shadow-[0_0_30px_rgba(220,38,38,0.6)] shrink-0">
                <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <div className="text-center sm:text-left">
                <h2 className="text-2xl font-black text-red-400 uppercase tracking-tighter">KAMU TERDETEKSI IDLE!</h2>
                <p className="text-slate-200 mt-2 text-lg">Sudah lebih dari 15 menit kamu tidak beraktivitas. <span className="text-red-300 font-bold">Waktu terus berjalan!</span> Selesaikan misi atau mulai timer sekarang.</p>
                <div className="flex justify-center sm:justify-start gap-4 mt-6">
                  <button 
                    onClick={(e) => { 
                      e.stopPropagation();
                      window.scrollTo({ top: 400, behavior: 'smooth' }); 
                      setShowIdleWarning(false);
                      setIsWarningDismissed(true);
                    }}
                    className="bg-red-600 hover:bg-red-500 text-white font-black py-3 px-8 rounded-2xl transition-all shadow-xl shadow-red-900/40 uppercase tracking-wide"
                  >
                    Mulai Sekarang
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* AI Nudge Notification with Enhanced pulse-intense */}
        {nudge && (
          <div className="bg-indigo-600 shadow-2xl shadow-indigo-900/60 p-8 rounded-[40px] flex items-start gap-6 animate-in slide-in-from-top-6 duration-500 border border-indigo-400/40 backdrop-blur-xl group hover:scale-[1.02] transition-transform">
            <div className="bg-white/20 p-4 rounded-3xl animate-pulse-intense shrink-0">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-3 mb-2">
                <span className="px-3 py-1 bg-red-500 text-[10px] font-black rounded-lg text-white animate-bounce-subtle tracking-tighter">URGENT MESSAGE</span>
                <h5 className="font-bold text-white/70 text-xs uppercase tracking-[0.2em]">Assistant Voice</h5>
              </div>
              <p className="text-white text-xl leading-tight font-black italic drop-shadow-md">"{nudge}"</p>
            </div>
            <button onClick={(e) => { e.stopPropagation(); setNudge(null); }} className="text-white/40 hover:text-white p-2 transition-colors">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}

        {/* Settings View */}
        {showSettings && (
          <div className="glass p-10 rounded-[40px] space-y-8 border border-indigo-500/20 shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black uppercase tracking-tighter">Productivity Setup</h3>
              <span className="px-3 py-1 bg-indigo-500/20 text-indigo-400 text-xs font-black rounded-lg uppercase">Aggressive Mode</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">Start Shift (Jam Mulai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.start}
                  onChange={(e) => updateHours({ ...state.productivityHours, start: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">End Shift (Jam Selesai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.end}
                  onChange={(e) => updateHours({ ...state.productivityHours, end: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
            </div>
            <div className="p-6 bg-indigo-500/10 rounded-3xl border border-indigo-500/10">
              <p className="text-sm text-indigo-200/80 leading-relaxed">
                <span className="font-black text-indigo-400 uppercase mr-2">ProActive Rule:</span> 
                Saya akan otomatis cerewet jika kamu terdeteksi diam saja selama 15 menit di jam produktifmu. Tidak ada hari tanpa progress! 🔥
              </p>
            </div>
            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-indigo-600 hover:bg-indigo-500 py-5 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all uppercase tracking-widest"
            >
              Update Protocol
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
          {/* Left/Middle Column: Dashboard & Timer */}
          <div className="lg:col-span-2 space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
               <TimerComponent onComplete={handleTimerComplete} onStatusChange={handleTimerStatus} />
               <div className="space-y-6">
                 <CalendarView tasks={state.tasks} />
                 <div className="p-8 glass rounded-3xl border border-white/5 bg-gradient-to-br from-indigo-500/5 to-transparent">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <h4 className="font-bold text-xs text-slate-500 uppercase tracking-widest">Total Progress</h4>
                      <p className="text-4xl font-black tracking-tighter">
                        {state.tasks.length > 0 ? Math.round((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100) : 0}%
                      </p>
                    </div>
                    <p className="text-[10px] text-slate-500 font-bold mb-2">
                      {state.tasks.filter(t => t.isCompleted).length} / {state.tasks.length} MISSION CLEARED
                    </p>
                  </div>
                  <div className="w-full h-4 bg-slate-900/50 rounded-full overflow-hidden p-1 shadow-inner">
                    <div 
                      className="h-full bg-gradient-to-r from-indigo-600 via-indigo-400 to-cyan-400 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(99,102,241,0.6)]" 
                      style={{ width: `${state.tasks.length > 0 ? Math.min((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100, 100) : 0}%` }}
                    ></div>
                  </div>
                </div>
               </div>
            </div>

             {/* Right Column: Tasks (Move to separate col on large, stays in flow on small) */}
            <div className="lg:hidden" onClick={(e) => e.stopPropagation()}>
               <TaskList 
                tasks={state.tasks} 
                onAddTask={addTask} 
                onToggleTask={toggleTask} 
                onDeleteTask={deleteTask} 
              />
            </div>
          </div>

          {/* Large Screen Task Column */}
          <div className="hidden lg:block sticky top-28" onClick={(e) => e.stopPropagation()}>
            <TaskList 
              tasks={state.tasks} 
              onAddTask={addTask} 
              onToggleTask={toggleTask} 
              onDeleteTask={deleteTask} 
            />
          </div>
        </div>
      </main>

      {/* Global CSS for Animations */}
      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        @keyframes pulse-intense {
          0% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
          50% { transform: scale(1.1); background-color: rgba(249, 115, 22, 0.6); }
          100% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-4px); }
          20%, 40%, 60%, 80% { transform: translateX(4px); }
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 1.5s ease-in-out infinite;
        }
        .animate-pulse-intense {
          animation: pulse-intense 0.8s ease-in-out infinite;
        }
        .animate-shake {
          animation: shake 0.6s cubic-bezier(.36,.07,.19,.97) both;
          animation-iteration-count: 1.5;
        }
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
        input[type="date"]::-webkit-calendar-picker-indicator {
          filter: invert(1);
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { CalendarView } from './components/CalendarView';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [idleStartTime, setIdleStartTime] = useState<number>(Date.now());
  const [showIdleWarning, setShowIdleWarning] = useState(false);
  const [isWarningDismissed, setIsWarningDismissed] = useState(false);
  const [isNudging, setIsNudging] = useState(false);

  const idleCheckInterval = useRef<number | null>(null);
  const reminderCheckInterval = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Request Notification Permission
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  // Audio utility for alerts
  const playAlertSound = useCallback(() => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine';
      osc.frequency.setValueAtTime(880, ctx.currentTime); // A5
      osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.5); // A4

      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.5);
    } catch (e) {
      console.warn("Audio play failed:", e);
    }
  }, []);

  const triggerVibration = useCallback(() => {
    if ('vibrate' in navigator) {
      navigator.vibrate([200, 100, 200, 100, 500]);
    }
    // Visual "screen shake" effect is handled by CSS class toggling or standard animations
    document.body.classList.add('screen-shake');
    setTimeout(() => document.body.classList.remove('screen-shake'), 1000);
  }, []);

  // Reset idle timer whenever user is "active"
  const recordActivity = useCallback(() => {
    const wasIdle = Date.now() - idleStartTime > 15 * 60 * 1000;
    setIdleStartTime(Date.now());
    setShowIdleWarning(false);
    if (wasIdle || isWarningDismissed) {
      setIsWarningDismissed(false);
    }
  }, [idleStartTime, isWarningDismissed]);

  const triggerManualNudge = async () => {
    recordActivity();
    setIsNudging(true);
    const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
    const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, false);
    setNudge(aiMessage || "Semangat! Kamu pasti bisa menyelesaikan semua misi hari ini! 💪");
    setIsNudging(false);
    setTimeout(() => setNudge(null), 10000);
  };

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    recordActivity();
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    recordActivity();
    playAlertSound();
    triggerVibration();

    if (mode === TimerMode.BREAK) {
      setNudge("Istirahat selesai! 🍵 Baterai sudah full? Sekarang waktunya kembali ke mode serius. Selesaikan satu misi besarmu sekarang juga! 🚀🔥");
    } else {
      const messages = {
        [TimerMode.FOCUS]: "Woi! Sesi fokus kelar. Istirahat 5 menit, jangan keterusan scrolling! 🍵",
        [TimerMode.PHYSICAL]: "Olahraga mantap! Keringetan itu sehat. Rehat dikit terus balik lagi! 💪",
        [TimerMode.BREAK]: "" 
      };
      setNudge(messages[mode] || "Timer Selesai!");
    }
    setTimeout(() => setNudge(null), 15000);

    if (Notification.permission === 'granted') {
      new Notification("Timer Selesai!", {
        body: mode === TimerMode.BREAK ? "Waktunya balik kerja!" : "Waktunya istirahat!",
        icon: "/favicon.ico"
      });
    }
  }, [recordActivity, playAlertSound, triggerVibration]);

  const handleTimerStatus = (active: boolean) => {
    setIsTimerActive(active);
    if (active) recordActivity();
  };

  // Task Reminder Checker
  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

      state.tasks.forEach(task => {
        if (!task.isCompleted && task.dueDate === todayStr && task.reminderTime === currentTimeStr) {
          // Play sound and show notification
          playAlertSound();
          if (Notification.permission === 'granted') {
            new Notification(`Reminder Misi: ${task.title}`, {
              body: `Waktunya mengerjakan misi "${task.title}"! Jangan ditunda lagi. 🔥`,
              tag: `task-${task.id}`
            });
          }
          // Also set nudge for UI visibility
          setNudge(`Waktunya Misi: "${task.title}"! 🔥`);
        }
      });
    };

    reminderCheckInterval.current = window.setInterval(checkReminders, 60000); // Check every minute
    return () => {
      if (reminderCheckInterval.current) clearInterval(reminderCheckInterval.current);
    };
  }, [state.tasks, playAlertSound]);

  // Idle and Proactive Nudging Logic
  useEffect(() => {
    const checkStatus = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      const isWithinHours = currentTimeStr >= start && currentTimeStr <= end;

      if (isWithinHours) {
        if (!isTimerActive) {
          const currentTimeMs = Date.now();
          const idleDuration = currentTimeMs - idleStartTime;

          if (idleDuration > 15 * 60 * 1000 && !isWarningDismissed) {
            setShowIdleWarning(true);
            triggerVibration(); // Subtle vibrate on warning trigger
          }

          const timeSinceLastNudge = currentTimeMs - state.lastNudgeTime;
          if (timeSinceLastNudge > 30 * 60 * 1000) { 
            const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
            const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, true);
            setNudge(aiMessage || "Ini jam produktifmu! Ayo mulai bergerak!");
            setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
          }
        } else {
          setShowIdleWarning(false);
        }
      } else {
        setShowIdleWarning(false);
      }
    };

    idleCheckInterval.current = window.setInterval(checkStatus, 60 * 1000);
    return () => {
      if (idleCheckInterval.current) clearInterval(idleCheckInterval.current);
    };
  }, [state.productivityHours, state.tasks, state.lastNudgeTime, isTimerActive, idleStartTime, isWarningDismissed, triggerVibration]);

  return (
    <div className="min-h-screen pb-12 bg-[#0f172a] selection:bg-indigo-500/30 transition-transform duration-100" onClick={recordActivity}>
      <header className="p-6 sticky top-0 z-50 glass">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-900/40">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
                PROACTIVE
              </h1>
              <p className="text-[9px] uppercase tracking-widest font-bold text-slate-500">Bossy Assistant</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:block text-right">
                <p className="text-[10px] text-slate-500 font-bold uppercase">Jam Produktif</p>
                <p className="text-xs font-semibold text-indigo-400">{state.productivityHours.start} - {state.productivityHours.end}</p>
             </div>
            <button 
              onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
              className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all group"
            >
              <svg className="w-5 h-5 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 mt-8 space-y-8">
        <div className="flex justify-center">
          <button 
            disabled={isNudging}
            onClick={(e) => { e.stopPropagation(); triggerManualNudge(); }}
            className={`flex items-center gap-3 px-10 py-5 bg-gradient-to-r from-indigo-500 to-indigo-700 hover:from-indigo-400 hover:to-indigo-600 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all active:scale-95 ${isNudging ? 'animate-pulse opacity-70' : 'hover:-translate-y-1'}`}
          >
            <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <span className="tracking-tight uppercase">{isNudging ? 'MENGHUBUNGI ASISTEN...' : 'NUDGE ME!'}</span>
          </button>
        </div>

        {showIdleWarning && (
          <div className="relative overflow-hidden bg-red-600/20 border border-red-500/30 rounded-3xl p-8 shadow-2xl shadow-red-900/30 animate-in fade-in zoom-in duration-300 animate-shake">
            <div className="absolute top-0 right-0 p-4">
              <button 
                onClick={(e) => { 
                  e.stopPropagation(); 
                  setShowIdleWarning(false); 
                  setIsWarningDismissed(true); 
                }}
                className="text-red-400 hover:text-red-200 transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
