{
  "name": "Re-Mager",
  "description": "A productivity assistant that proactively pushes you to stay active, manages tasks with smart reminders, and features a color-coded focus timer to combat laziness.",
  "requestFramePermissions": []
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getNudgeMessage = async (tasks: string[], productivityHours: { start: string; end: string }, isIdle: boolean) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User is currently in their productivity hours (${productivityHours.start} - ${productivityHours.end}). 
      Pending tasks: ${tasks.join(', ') || 'Nothing listed yet'}.
      Status: ${isIdle ? 'User is IDLE (not using timer, no recent tasks done)' : 'User is active but needs a push'}.

      Act as "Re-Mager", the ultimate Anti-Mager (Anti-Lazy) assistant. Your personality is "cerewet" (nagging), high-energy, and funny in Indonesian. 
      Combat "mager" (laziness) at all costs!

      If idle: Strongly nudge them to stop being mager. Remind them their future self is watching.
      If not idle: Keep them fired up.

      Limit to 2-3 sentences. Use emojis like 🔥, 🚀, 💪, 😤.`,
      config: {
        temperature: 1.0,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Woi! Jangan mager terus! Ini jam produktif kamu. Ayo gerak sekarang sebelum disalip orang lain! 🔥";
  }
};

export const getTaskRecommendation = async (task: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Task: "${task}". 
      As the Re-Mager coach, recommend the absolute best time of day for this specific task (morning/afternoon/evening) and WHY.
      Provide one specific "hack" to fight procrastination (anti-mager tip) in Indonesian.
      Keep it punchy, funny, and bossy.`,
      config: {
        temperature: 0.8,
      }
    });
    return response.text;
  } catch (error) {
    return "Kerjain SEKARANG. Gak usah nunggu mood, mood itu dicari lewat aksi! 💪";
  }
};

import React, { useState } from 'react';
import { Task } from '../types';

interface CalendarViewProps {
  tasks: Task[];
}

export const CalendarView: React.FC<CalendarViewProps> = ({ tasks }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  // Generate days for the current month
  const getDaysInMonth = (year: number, month: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const currentYear = viewDate.getFullYear();
  const currentMonth = viewDate.getMonth();
  const daysInMonth = getDaysInMonth(currentYear, currentMonth);
  const firstDayOfMonth = new Date(currentYear, currentMonth, 1).getDay();

  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const emptyDays = Array.from({ length: firstDayOfMonth }, (_, i) => i);

  const monthName = viewDate.toLocaleString('id-ID', { month: 'long' });

  const tasksByDate = tasks.reduce((acc, task) => {
    const date = task.dueDate;
    if (!acc[date]) acc[date] = [];
    acc[date].push(task);
    return acc;
  }, {} as Record<string, Task[]>);

  const changeMonth = (delta: number) => {
    const newDate = new Date(viewDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setViewDate(newDate);
  };

  const todayStr = new Date().toISOString().split('T')[0];

  const handleDayClick = (dateStr: string) => {
    setSelectedDate(dateStr);
  };

  return (
    <div className="glass p-6 rounded-3xl border border-white/5 space-y-4 relative">
      <div className="flex items-center justify-between mb-2">
        <h3 className="font-black text-xl uppercase tracking-tighter">Mission Schedule</h3>
        <div className="flex gap-2">
          <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7"/></svg>
          </button>
          <span className="font-bold min-w-[120px] text-center text-sm">{monthName} {currentYear}</span>
          <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7"/></svg>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-1">
        {['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'].map(day => (
          <div key={day} className="text-center text-[10px] font-black text-slate-500 uppercase py-2">{day}</div>
        ))}
        {emptyDays.map(d => <div key={`empty-${d}`} className="aspect-square"></div>)}
        {days.map(day => {
          const dateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
          const dayTasks = tasksByDate[dateStr] || [];
          const isToday = dateStr === todayStr;
          const isOverdue = dayTasks.some(t => !t.isCompleted && dateStr < todayStr);

          return (
            <button 
              key={day} 
              onClick={() => handleDayClick(dateStr)}
              className={`aspect-square relative flex flex-col items-center justify-center rounded-xl border transition-all hover:bg-white/10 group 
                ${isToday ? 'bg-indigo-500/20 border-indigo-500/40' : 'border-white/5'}
                ${isOverdue ? 'border-red-500/50 shadow-[inset_0_0_10px_rgba(239,68,68,0.1)]' : ''}
                ${dayTasks.length > 0 ? 'cursor-pointer' : 'cursor-default'}
              `}
            >
              <span className={`text-xs font-bold 
                ${isToday ? 'text-indigo-400' : isOverdue ? 'text-red-400' : 'text-slate-400'}
              `}>
                {day}
              </span>
              {dayTasks.length > 0 && (
                <div className="flex gap-0.5 mt-1">
                  {dayTasks.slice(0, 3).map((t, i) => (
                    <div 
                      key={t.id} 
                      className={`w-1.5 h-1.5 rounded-full ${t.isCompleted ? 'bg-slate-600' : isOverdue ? 'bg-red-500' : 'bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,0.5)] animate-pulse'}`}
                    />
                  ))}
                  {dayTasks.length > 3 && <div className={`text-[8px] font-bold ${isOverdue ? 'text-red-400' : 'text-indigo-400'}`}>+</div>}
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Task Detail Modal */}
      {selectedDate && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 sm:p-6 bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="w-full max-w-md bg-slate-900 rounded-[2.5rem] border border-white/10 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-white/5 flex items-center justify-between bg-gradient-to-r from-indigo-600/10 to-transparent">
              <div>
                <h4 className="text-xl font-black uppercase tracking-tighter">Mission Details</h4>
                <p className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{selectedDate}</p>
              </div>
              <button 
                onClick={() => setSelectedDate(null)}
                className="p-2 hover:bg-white/5 rounded-xl transition-all text-slate-400 hover:text-white"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-4 no-scrollbar">
              {tasksByDate[selectedDate] && tasksByDate[selectedDate].length > 0 ? (
                tasksByDate[selectedDate].map(task => (
                  <div key={task.id} className={`p-4 rounded-2xl border ${task.isCompleted ? 'bg-slate-800/30 border-white/5 opacity-50' : 'bg-slate-800/60 border-indigo-500/20'}`}>
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-[10px] font-black uppercase px-2 py-0.5 bg-indigo-500 text-white rounded-md">{task.category}</span>
                      {task.reminderTime && <span className="text-[10px] font-bold text-orange-400">⏰ {task.reminderTime}</span>}
                    </div>
                    <h5 className={`font-bold ${task.isCompleted ? 'line-through text-slate-500' : 'text-white'}`}>{task.title}</h5>
                    <div className="mt-2 flex items-center gap-2">
                       <div className={`w-2 h-2 rounded-full ${task.isCompleted ? 'bg-slate-500' : 'bg-green-500 animate-pulse'}`}></div>
                       <span className="text-[10px] font-bold uppercase text-slate-500">{task.isCompleted ? 'Completed' : 'Pending'}</span>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-10">
                  <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
                    <svg className="w-8 h-8 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <p className="text-slate-500 font-bold">Tidak ada misi di hari ini.</p>
                </div>
              )}
            </div>

            <div className="p-6 bg-slate-900/50 border-t border-white/5">
              <button 
                onClick={() => setSelectedDate(null)}
                className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-black text-white transition-all uppercase tracking-widest text-sm shadow-xl shadow-indigo-900/20"
              >
                Close Details
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { CalendarView } from './components/CalendarView';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [idleStartTime, setIdleStartTime] = useState<number>(Date.now());
  const [showIdleWarning, setShowIdleWarning] = useState(false);
  const [isWarningDismissed, setIsWarningDismissed] = useState(false);
  const [isNudging, setIsNudging] = useState(false);
  const [isAlarmActive, setIsAlarmActive] = useState(false);

  const idleCheckInterval = useRef<number | null>(null);
  const reminderCheckInterval = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Request Notification Permission
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  // Audio utility for alerts - Enhanced for persistence
  const playSingleAlertTone = useCallback(() => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') ctx.resume();

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'triangle';
      osc.frequency.setValueAtTime(523.25, ctx.currentTime); // C5
      osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.1); // A5

      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.4);
    } catch (e) {
      console.warn("Audio play failed:", e);
    }
  }, []);

  const triggerVibration = useCallback(() => {
    if ('vibrate' in navigator) {
      navigator.vibrate([300, 100, 300, 100, 300]);
    }
    document.body.classList.add('screen-shake');
    setTimeout(() => document.body.classList.remove('screen-shake'), 500);
  }, []);

  const stopAlarm = useCallback(() => {
    setIsAlarmActive(false);
    if (alarmIntervalRef.current) {
      clearInterval(alarmIntervalRef.current);
      alarmIntervalRef.current = null;
    }
    document.body.classList.remove('screen-shake-persistent');
  }, []);

  const startPersistentAlarm = useCallback(() => {
    setIsAlarmActive(true);
    document.body.classList.add('screen-shake-persistent');

    // Immediate first trigger
    playSingleAlertTone();
    triggerVibration();

    // Repeat every 1.5 seconds until dismissed
    alarmIntervalRef.current = window.setInterval(() => {
      playSingleAlertTone();
      triggerVibration();
    }, 1500);
  }, [playSingleAlertTone, triggerVibration]);

  // Reset idle timer whenever user is "active"
  const recordActivity = useCallback(() => {
    const wasIdle = Date.now() - idleStartTime > 15 * 60 * 1000;
    setIdleStartTime(Date.now());
    setShowIdleWarning(false);
    if (wasIdle || isWarningDismissed) {
      setIsWarningDismissed(false);
    }
  }, [idleStartTime, isWarningDismissed]);

  const triggerManualNudge = async () => {
    recordActivity();
    setIsNudging(true);
    const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
    const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, false);
    setNudge(aiMessage || "Semangat! Kamu pasti bisa menyelesaikan semua misi hari ini! 💪");
    setIsNudging(false);
    setTimeout(() => setNudge(null), 10000);
  };

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    recordActivity();
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    recordActivity();
    startPersistentAlarm();

    if (mode === TimerMode.BREAK) {
      setNudge("Istirahat selesai! 🍵 Waktunya balik ke mode serius. Selesaikan satu misi besarmu sekarang juga! 🚀🔥");
    } else {
      const messages = {
        [TimerMode.FOCUS]: "Woi! Sesi fokus kelar. Istirahat 5 menit, jangan keterusan scrolling! 🍵",
        [TimerMode.PHYSICAL]: "Olahraga mantap! Keringetan itu sehat. Rehat dikit terus balik lagi! 💪",
        [TimerMode.BREAK]: "" 
      };
      setNudge(messages[mode] || "Timer Selesai!");
    }

    if (Notification.permission === 'granted') {
      new Notification("Timer Selesai!", {
        body: mode === TimerMode.BREAK ? "Waktunya balik kerja!" : "Waktunya istirahat!",
        icon: "/favicon.ico",
        requireInteraction: true 
      });
    }
  }, [recordActivity, startPersistentAlarm]);

  const handleTimerStatus = (active: boolean) => {
    setIsTimerActive(active);
    if (active) recordActivity();
  };

  // Task Reminder Checker
  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

      state.tasks.forEach(task => {
        if (!task.isCompleted && task.dueDate === todayStr && task.reminderTime === currentTimeStr) {
          startPersistentAlarm();
          if (Notification.permission === 'granted') {
            new Notification(`Reminder Misi: ${task.title}`, {
              body: `Waktunya mengerjakan misi "${task.title}"! 🔥`,
              tag: `task-${task.id}`,
              requireInteraction: true
            });
          }
          setNudge(`Waktunya Misi: "${task.title}"! 🔥`);
        }
      });
    };

    reminderCheckInterval.current = window.setInterval(checkReminders, 60000);
    return () => {
      if (reminderCheckInterval.current) clearInterval(reminderCheckInterval.current);
    };
  }, [state.tasks, startPersistentAlarm]);

  // Idle and Proactive Nudging Logic
  useEffect(() => {
    const checkStatus = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      const isWithinHours = currentTimeStr >= start && currentTimeStr <= end;

      if (isWithinHours) {
        if (!isTimerActive) {
          const currentTimeMs = Date.now();
          const idleDuration = currentTimeMs - idleStartTime;

          if (idleDuration > 15 * 60 * 1000 && !isWarningDismissed) {
            setShowIdleWarning(true);
            triggerVibration(); 
          }

          const timeSinceLastNudge = currentTimeMs - state.lastNudgeTime;
          if (timeSinceLastNudge > 30 * 60 * 1000) { 
            const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
            const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, true);
            setNudge(aiMessage || "Ini jam produktifmu! Ayo mulai bergerak!");
            setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
          }
        } else {
          setShowIdleWarning(false);
        }
      } else {
        setShowIdleWarning(false);
      }
    };

    idleCheckInterval.current = window.setInterval(checkStatus, 60 * 1000);
    return () => {
      if (idleCheckInterval.current) clearInterval(idleCheckInterval.current);
    };
  }, [state.productivityHours, state.tasks, state.lastNudgeTime, isTimerActive, idleStartTime, isWarningDismissed, triggerVibration]);

  return (
    <div className="min-h-screen pb-12 bg-[#0f172a] selection:bg-indigo-500/30 transition-transform duration-100" onClick={recordActivity}>

      {/* GLOBAL PERSISTENT ALARM OVERLAY */}
      {isAlarmActive && (
        <div className="fixed inset-0 z-[150] bg-red-600/90 backdrop-blur-xl flex flex-col items-center justify-center p-6 text-center animate-in fade-in duration-300">
          <div className="w-32 h-32 bg-white rounded-full flex items-center justify-center mb-8 animate-bounce-subtle shadow-[0_0_50px_rgba(255,255,255,0.8)]">
             <svg className="w-16 h-16 text-red-600 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
             </svg>
          </div>
          <h2 className="text-4xl sm:text-6xl font-black text-white uppercase tracking-tighter mb-4 drop-shadow-lg">WAKTU SELESAI!</h2>
          <p className="text-xl sm:text-2xl text-red-100 font-bold mb-12 max-w-md">Woi! Bangun! Jangan mager doang! Misimu butuh perhatian segera!</p>
          <button 
            onClick={stopAlarm}
            className="group relative px-16 py-6 bg-white hover:bg-slate-100 text-red-600 font-black text-3xl rounded-[2rem] shadow-2xl transition-all active:scale-95 hover:scale-105"
          >
            STOP ALARM
            <div className="absolute inset-0 rounded-[2rem] border-4 border-white animate-ping opacity-50"></div>
          </button>
        </div>
      )}

      {/* Header */}
      <header className="p-6 sticky top-0 z-50 glass">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-900/40">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
                RE-MAGER
              </h1>
              <p className="text-[9px] uppercase tracking-widest font-bold text-slate-500">Anti-Mager Assistant</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:block text-right">
                <p className="text-[10px] text-slate-500 font-bold uppercase">Jam Produktif</p>
                <p className="text-xs font-semibold text-indigo-400">{state.productivityHours.start} - {state.productivityHours.end}</p>
             </div>
            <button 
              onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
              className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all group"
            >
              <svg className="w-5 h-5 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 mt-8 space-y-8">
        <div className="flex justify-center">
          <button 
            disabled={isNudging}
            onClick={(e) => { e.stopPropagation(); triggerManualNudge(); }}
            className={`flex items-center gap-3 px-10 py-5 bg-gradient-to-r from-indigo-500 to-indigo-700 hover:from-indigo-400 hover:to-indigo-600 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all active:scale-95 ${isNudging ? 'animate-pulse opacity-70' : 'hover:-translate-y-1'}`}
          >
            <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <span className="tracking-tight uppercase">{isNudging ? 'HUBUNGI ANTI-MAGER...' : 'NUDGE ME!'}</span>
          </button>
        </div>

        {showIdleWarning && (
          <div className="relative overflow-hidden bg-red-600/20 border border-red-500/30 rounded-3xl p-8 shadow-2xl shadow-red-900/30 animate-in fade-in zoom-in duration-300 animate-shake">
            <div className="absolute top-0 right-0 p-4">
              <button 
                onClick={(e) => { 
                  e.stopPropagation(); 
                  setShowIdleWarning(false); 
                  setIsWarningDismissed(true); 
                }}
                className="text-red-400 hover:text-red-200 transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div className="flex flex-col sm:flex-row items-center gap-8">
              <div className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center animate-pulse shadow-[0_0_30px_rgba(220,38,38,0.6)] shrink-0">
                <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <div className="text-center sm:text-left">
                <h2 className="text-2xl font-black text-red-400 uppercase tracking-tighter">STOP MAGER! KAMU IDLE!</h2>
                <p className="text-slate-200 mt-2 text-lg">Sudah lebih dari 15 menit kamu diam saja. <span className="text-red-300 font-bold">Waktu produktifmu terbuang!</span> Selesaikan misi atau mulai timer sekarang.</p>
                <div className="flex justify-center sm:justify-start gap-4 mt-6">
                  <button 
                    onClick={(e) => { 
                      e.stopPropagation();
                      window.scrollTo({ top: 400, behavior: 'smooth' }); 
                      setShowIdleWarning(false);
                      setIsWarningDismissed(true);
                    }}
                    className="bg-red-600 hover:bg-red-500 text-white font-black py-3 px-8 rounded-2xl transition-all shadow-xl shadow-red-900/40 uppercase tracking-wide"
                  >
                    Saya Siap Bergerak
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {nudge && (
          <div className="bg-indigo-600 shadow-2xl shadow-indigo-900/60 p-8 rounded-[40px] flex items-start gap-6 animate-in slide-in-from-top-6 duration-500 border border-indigo-400/40 backdrop-blur-xl group hover:scale-[1.02] transition-transform">
            <div className="bg-white/20 p-4 rounded-3xl animate-pulse-intense shrink-0">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-3 mb-2">
                <span className="px-3 py-1 bg-red-500 text-[10px] font-black rounded-lg text-white animate-bounce-subtle tracking-tighter uppercase">Anti-Mager Nudge</span>
                <h5 className="font-bold text-white/70 text-xs uppercase tracking-[0.2em]">Assistant Voice</h5>
              </div>
              <p className="text-white text-xl leading-tight font-black italic drop-shadow-md">"{nudge}"</p>
            </div>
            <button onClick={(e) => { e.stopPropagation(); setNudge(null); }} className="text-white/40 hover:text-white p-2 transition-colors">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}

        {showSettings && (
          <div className="glass p-10 rounded-[40px] space-y-8 border border-indigo-500/20 shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black uppercase tracking-tighter">Anti-Mager Setup</h3>
              <span className="px-3 py-1 bg-indigo-500/20 text-indigo-400 text-xs font-black rounded-lg uppercase">Aggressive Mode</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">Start Shift (Jam Mulai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.start}
                  onChange={(e) => updateHours({ ...state.productivityHours, start: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">End Shift (Jam Selesai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.end}
                  onChange={(e) => updateHours({ ...state.productivityHours, end: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
            </div>
            <div className="p-6 bg-indigo-500/10 rounded-3xl border border-indigo-500/10">
              <p className="text-sm text-indigo-200/80 leading-relaxed">
                <span className="font-black text-indigo-400 uppercase mr-2">Re-Mager Protocol:</span> 
                Saya akan otomatis cerewet jika kamu terdeteksi diam saja selama 15 menit di jam produktifmu. Lawan rasa mager, raih mimpimu! 🔥
              </p>
            </div>
            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-indigo-600 hover:bg-indigo-500 py-5 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all uppercase tracking-widest"
            >
              Update Protocol
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
          <div className="lg:col-span-2 space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
               <TimerComponent onComplete={handleTimerComplete} onStatusChange={handleTimerStatus} />
               <div className="space-y-6">
                 <CalendarView tasks={state.tasks} />
                 <div className="p-8 glass rounded-3xl border border-white/5 bg-gradient-to-br from-indigo-500/5 to-transparent">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <h4 className="font-bold text-xs text-slate-500 uppercase tracking-widest">Total Progress</h4>
                      <p className="text-4xl font-black tracking-tighter">
                        {state.tasks.length > 0 ? Math.round((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100) : 0}%
                      </p>
                    </div>
                    <p className="text-[10px] text-slate-500 font-bold mb-2 uppercase">
                      {state.tasks.filter(t => t.isCompleted).length} / {state.tasks.length} MISSION CLEARED
                    </p>
                  </div>
                  <div className="w-full h-4 bg-slate-900/50 rounded-full overflow-hidden p-1 shadow-inner">
                    <div 
                      className="h-full bg-gradient-to-r from-indigo-600 via-indigo-400 to-cyan-400 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(99,102,241,0.6)]" 
                      style={{ width: `${state.tasks.length > 0 ? Math.min((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100, 100) : 0}%` }}
                    ></div>
                  </div>
                </div>
               </div>
            </div>

            <div className="lg:hidden" onClick={(e) => e.stopPropagation()}>
               <TaskList 
                tasks={state.tasks} 
                onAddTask={addTask} 
                onToggleTask={toggleTask} 
                onDeleteTask={deleteTask} 
              />
            </div>
          </div>

          <div className="hidden lg:block sticky top-28" onClick={(e) => e.stopPropagation()}>
            <TaskList 
              tasks={state.tasks} 
              onAddTask={addTask} 
              onToggleTask={toggleTask} 
              onDeleteTask={deleteTask} 
            />
          </div>
        </div>
      </main>

      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        @keyframes pulse-intense {
          0% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
          50% { transform: scale(1.1); background-color: rgba(249, 115, 22, 0.6); }
          100% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-4px); }
          20%, 40%, 60%, 80% { transform: translateX(4px); }
        }
        @keyframes screen-shake-anim {
          0%, 100% { transform: translate(0, 0); }
          25% { transform: translate(3px, -3px); }
          50% { transform: translate(-3px, 3px); }
          75% { transform: translate(3px, 3px); }
        }
        @keyframes screen-shake-persistent-anim {
          0%, 100% { transform: translate(0, 0) rotate(0); }
          20% { transform: translate(-8px, 8px) rotate(-1deg); }
          40% { transform: translate(-8px, -8px) rotate(1deg); }
          60% { transform: translate(8px, 8px) rotate(-1deg); }
          80% { transform: translate(8px, -8px) rotate(1deg); }
        }
        .screen-shake {
          animation: screen-shake-anim 0.1s infinite;
        }
        .screen-shake-persistent {
          animation: screen-shake-persistent-anim 0.1s infinite;
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 0.8s ease-in-out infinite;
        }
        .animate-pulse-intense {
          animation: pulse-intense 0.8s ease-in-out infinite;
        }
        .animate-shake {
          animation: shake 0.6s cubic-bezier(.36,.07,.19,.97) both;
          animation-iteration-count: 1.5;
        }
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
        input[type="date"]::-webkit-calendar-picker-indicator {
          filter: invert(1);
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimerComponent } from './components/TimerComponent';
import { TaskList } from './components/TaskList';
import { CalendarView } from './components/CalendarView';
import { TimerMode, Task, AppState, ProductivityHours } from './types';
import { getNudgeMessage } from './services/geminiService';

const STORAGE_KEY = 'proactive_timer_state';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      tasks: [],
      productivityHours: { start: '08:00', end: '18:00' },
      lastNudgeTime: 0
    };
  });

  const [nudge, setNudge] = useState<string | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [idleStartTime, setIdleStartTime] = useState<number>(Date.now());
  const [showIdleWarning, setShowIdleWarning] = useState(false);
  const [isWarningDismissed, setIsWarningDismissed] = useState(false);
  const [isNudging, setIsNudging] = useState(false);
  const [isAlarmActive, setIsAlarmActive] = useState(false);

  const idleCheckInterval = useRef<number | null>(null);
  const reminderCheckInterval = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Request Notification Permission
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  // Persistent, more aggressive two-tone alarm
  const playSingleAlertTone = useCallback(() => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      if (ctx.state === 'suspended') ctx.resume();

      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();

      osc1.type = 'square'; // Harsh square wave for Anti-Mager
      osc2.type = 'sawtooth';

      osc1.frequency.setValueAtTime(440, ctx.currentTime);
      osc1.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.2);

      osc2.frequency.setValueAtTime(330, ctx.currentTime);
      osc2.frequency.exponentialRampToValueAtTime(660, ctx.currentTime + 0.2);

      gain.gain.setValueAtTime(0.15, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

      osc1.connect(gain);
      osc2.connect(gain);
      gain.connect(ctx.destination);

      osc1.start();
      osc2.start();
      osc1.stop(ctx.currentTime + 0.5);
      osc2.stop(ctx.currentTime + 0.5);
    } catch (e) {
      console.warn("Audio play failed:", e);
    }
  }, []);

  const triggerVibration = useCallback(() => {
    if ('vibrate' in navigator) {
      navigator.vibrate([400, 100, 400, 100, 400]);
    }
    document.body.classList.add('screen-shake-persistent');
    setTimeout(() => {
        if (!isAlarmActive) document.body.classList.remove('screen-shake-persistent');
    }, 500);
  }, [isAlarmActive]);

  const stopAlarm = useCallback(() => {
    setIsAlarmActive(false);
    if (alarmIntervalRef.current) {
      clearInterval(alarmIntervalRef.current);
      alarmIntervalRef.current = null;
    }
    document.body.classList.remove('screen-shake-persistent');
  }, []);

  const startPersistentAlarm = useCallback(() => {
    if (isAlarmActive) return; // Don't stack alarms
    setIsAlarmActive(true);
    document.body.classList.add('screen-shake-persistent');

    playSingleAlertTone();
    triggerVibration();

    alarmIntervalRef.current = window.setInterval(() => {
      playSingleAlertTone();
      triggerVibration();
    }, 1200); // Faster repeat for more urgency
  }, [isAlarmActive, playSingleAlertTone, triggerVibration]);

  const recordActivity = useCallback(() => {
    const wasIdle = Date.now() - idleStartTime > 15 * 60 * 1000;
    setIdleStartTime(Date.now());
    setShowIdleWarning(false);
    if (wasIdle || isWarningDismissed) {
      setIsWarningDismissed(false);
    }
  }, [idleStartTime, isWarningDismissed]);

  const triggerManualNudge = async () => {
    recordActivity();
    setIsNudging(true);
    const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
    const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, false);
    setNudge(aiMessage || "Semangat! Kamu pasti bisa menyelesaikan semua misi hari ini! 💪");
    setIsNudging(false);
    setTimeout(() => setNudge(null), 10000);
  };

  const addTask = (taskData: Omit<Task, 'id' | 'createdAt' | 'isCompleted'>) => {
    recordActivity();
    const newTask: Task = {
      ...taskData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now(),
      isCompleted: false
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const toggleTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t)
    }));
  };

  const deleteTask = (id: string) => {
    recordActivity();
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== id)
    }));
  };

  const updateHours = (hours: ProductivityHours) => {
    setState(prev => ({ ...prev, productivityHours: hours }));
  };

  const handleTimerComplete = useCallback((mode: TimerMode) => {
    recordActivity();
    startPersistentAlarm();

    if (mode === TimerMode.BREAK) {
      setNudge("ISTIRAHAT SELESAI! 🍵 Jangan keenakan nyantai. Ayo balik ke mode produktif sekarang juga! 🚀🔥");
    } else {
      const messages = {
        [TimerMode.FOCUS]: "Sesi fokus kelar! Ambil napas, tapi jangan kebablasan scrolling! 🍵",
        [TimerMode.PHYSICAL]: "Workout done! Udah dapet dopamin kan? Gas lanjut kerja! 💪",
        [TimerMode.BREAK]: "" 
      };
      setNudge(messages[mode] || "Timer Selesai!");
    }

    if (Notification.permission === 'granted') {
      new Notification("WAKTU HABIS! 🔥", {
        body: mode === TimerMode.BREAK ? "Waktunya balik produktif!" : "Ambil istirahat sejenak!",
        icon: "/favicon.ico",
        requireInteraction: true 
      });
    }
  }, [recordActivity, startPersistentAlarm]);

  const handleTimerStatus = (active: boolean) => {
    setIsTimerActive(active);
    if (active) recordActivity();
  };

  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

      state.tasks.forEach(task => {
        if (!task.isCompleted && task.dueDate === todayStr && task.reminderTime === currentTimeStr) {
          startPersistentAlarm();
          if (Notification.permission === 'granted') {
            new Notification(`MISI DIMULAI: ${task.title}`, {
              body: `Stop mager! Waktunya eksekusi "${task.title}" sekarang! 🔥`,
              tag: `task-${task.id}`,
              requireInteraction: true
            });
          }
          setNudge(`MISSION CALL: "${task.title}"! 🔥`);
        }
      });
    };

    reminderCheckInterval.current = window.setInterval(checkReminders, 60000);
    return () => {
      if (reminderCheckInterval.current) clearInterval(reminderCheckInterval.current);
    };
  }, [state.tasks, startPersistentAlarm]);

  useEffect(() => {
    const checkStatus = async () => {
      const now = new Date();
      const currentTimeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const { start, end } = state.productivityHours;

      const isWithinHours = currentTimeStr >= start && currentTimeStr <= end;

      if (isWithinHours) {
        if (!isTimerActive) {
          const currentTimeMs = Date.now();
          const idleDuration = currentTimeMs - idleStartTime;

          if (idleDuration > 15 * 60 * 1000 && !isWarningDismissed) {
            setShowIdleWarning(true);
            triggerVibration(); 
          }

          const timeSinceLastNudge = currentTimeMs - state.lastNudgeTime;
          if (timeSinceLastNudge > 30 * 60 * 1000) { 
            const pendingTaskTitles = state.tasks.filter(t => !t.isCompleted).map(t => t.title);
            const aiMessage = await getNudgeMessage(pendingTaskTitles, state.productivityHours, true);
            setNudge(aiMessage || "Ayo gerak! Jangan biarkan hari ini lewat tanpa hasil!");
            setState(prev => ({ ...prev, lastNudgeTime: Date.now() }));
          }
        } else {
          setShowIdleWarning(false);
        }
      } else {
        setShowIdleWarning(false);
      }
    };

    idleCheckInterval.current = window.setInterval(checkStatus, 60 * 1000);
    return () => {
      if (idleCheckInterval.current) clearInterval(idleCheckInterval.current);
    };
  }, [state.productivityHours, state.tasks, state.lastNudgeTime, isTimerActive, idleStartTime, isWarningDismissed, triggerVibration]);

  return (
    <div className="min-h-screen pb-12 bg-[#0f172a] selection:bg-indigo-500/30 transition-transform duration-100" onClick={recordActivity}>

      {/* GLOBAL PERSISTENT ALARM OVERLAY - HIGHEST Z-INDEX */}
      {isAlarmActive && (
        <div className="fixed inset-0 z-[999] bg-red-600/95 backdrop-blur-2xl flex flex-col items-center justify-center p-6 text-center animate-in fade-in duration-300">
          <div className="w-40 h-40 bg-white rounded-full flex items-center justify-center mb-10 animate-bounce shadow-[0_0_80px_rgba(255,255,255,0.9)]">
             <svg className="w-20 h-20 text-red-600 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
             </svg>
          </div>
          <h2 className="text-5xl sm:text-7xl font-black text-white uppercase tracking-tighter mb-6 drop-shadow-2xl">BANGUN! STOP MAGER!</h2>
          <p className="text-2xl sm:text-3xl text-red-100 font-bold mb-16 max-w-xl leading-snug">Waktunya bergerak! Jangan biarkan kemalasan menang hari ini. 🔥</p>
          <button 
            onClick={stopAlarm}
            className="group relative px-20 py-8 bg-white hover:bg-slate-100 text-red-600 font-black text-4xl rounded-[3rem] shadow-[0_20px_60px_-15px_rgba(255,255,255,0.5)] transition-all active:scale-90 hover:scale-105"
          >
            SAYA SIAP! STOP ALARM
            <div className="absolute inset-0 rounded-[3rem] border-4 border-white animate-ping opacity-60"></div>
          </button>
        </div>
      )}

      {/* Header */}
      <header className="p-6 sticky top-0 z-50 glass">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-900/40">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-black bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
                RE-MAGER
              </h1>
              <p className="text-[9px] uppercase tracking-widest font-bold text-slate-500">Anti-Mager Assistant</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:block text-right">
                <p className="text-[10px] text-slate-500 font-bold uppercase">Jam Produktif</p>
                <p className="text-xs font-semibold text-indigo-400">{state.productivityHours.start} - {state.productivityHours.end}</p>
             </div>
            <button 
              onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
              className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all group"
            >
              <svg className="w-5 h-5 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 mt-8 space-y-8">
        <div className="flex justify-center">
          <button 
            disabled={isNudging}
            onClick={(e) => { e.stopPropagation(); triggerManualNudge(); }}
            className={`flex items-center gap-3 px-10 py-5 bg-gradient-to-r from-indigo-500 to-indigo-700 hover:from-indigo-400 hover:to-indigo-600 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all active:scale-95 ${isNudging ? 'animate-pulse opacity-70' : 'hover:-translate-y-1'}`}
          >
            <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <span className="tracking-tight uppercase">{isNudging ? 'MENGHUBUNGI ASISTEN...' : 'NUDGE ME!'}</span>
          </button>
        </div>

        {showIdleWarning && (
          <div className="relative overflow-hidden bg-red-600/20 border border-red-500/30 rounded-3xl p-8 shadow-2xl shadow-red-900/30 animate-in fade-in zoom-in duration-300 animate-shake">
            <div className="absolute top-0 right-0 p-4">
              <button 
                onClick={(e) => { 
                  e.stopPropagation(); 
                  setShowIdleWarning(false); 
                  setIsWarningDismissed(true); 
                }}
                className="text-red-400 hover:text-red-200 transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div className="flex flex-col sm:flex-row items-center gap-8">
              <div className="w-20 h-20 bg-red-600 rounded-full flex items-center justify-center animate-pulse shadow-[0_0_30px_rgba(220,38,38,0.6)] shrink-0">
                <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <div className="text-center sm:text-left">
                <h2 className="text-2xl font-black text-red-400 uppercase tracking-tighter">STOP MAGER! KAMU IDLE!</h2>
                <p className="text-slate-200 mt-2 text-lg">Sudah lebih dari 15 menit kamu diam saja. <span className="text-red-300 font-bold">Waktu produktifmu terbuang!</span></p>
                <div className="flex justify-center sm:justify-start gap-4 mt-6">
                  <button 
                    onClick={(e) => { 
                      e.stopPropagation();
                      window.scrollTo({ top: 400, behavior: 'smooth' }); 
                      setShowIdleWarning(false);
                      setIsWarningDismissed(true);
                    }}
                    className="bg-red-600 hover:bg-red-500 text-white font-black py-3 px-8 rounded-2xl transition-all shadow-xl shadow-red-900/40 uppercase tracking-wide"
                  >
                    Saya Siap Bergerak
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {nudge && (
          <div className="bg-indigo-600 shadow-2xl shadow-indigo-900/60 p-8 rounded-[40px] flex items-start gap-6 animate-in slide-in-from-top-6 duration-500 border border-indigo-400/40 backdrop-blur-xl group hover:scale-[1.02] transition-transform">
            <div className="bg-white/20 p-4 rounded-3xl animate-pulse-intense shrink-0">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-3 mb-2">
                <span className="px-3 py-1 bg-red-500 text-[10px] font-black rounded-lg text-white animate-bounce-subtle tracking-tighter uppercase">Anti-Mager Nudge</span>
                <h5 className="font-bold text-white/70 text-xs uppercase tracking-[0.2em]">Assistant Voice</h5>
              </div>
              <p className="text-white text-xl leading-tight font-black italic drop-shadow-md">"{nudge}"</p>
            </div>
            <button onClick={(e) => { e.stopPropagation(); setNudge(null); }} className="text-white/40 hover:text-white p-2 transition-colors">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}

        {showSettings && (
          <div className="glass p-10 rounded-[40px] space-y-8 border border-indigo-500/20 shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black uppercase tracking-tighter">Anti-Mager Setup</h3>
              <span className="px-3 py-1 bg-indigo-500/20 text-indigo-400 text-xs font-black rounded-lg uppercase">Aggressive Mode</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">Start Shift (Jam Mulai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.start}
                  onChange={(e) => updateHours({ ...state.productivityHours, start: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest block">End Shift (Jam Selesai)</label>
                <input 
                  type="time" 
                  value={state.productivityHours.end}
                  onChange={(e) => updateHours({ ...state.productivityHours, end: e.target.value })}
                  className="w-full bg-slate-900/70 p-5 rounded-3xl border border-slate-700 outline-none focus:border-indigo-500 transition-all text-2xl font-black text-indigo-400" 
                />
              </div>
            </div>
            <div className="p-6 bg-indigo-500/10 rounded-3xl border border-indigo-500/10">
              <p className="text-sm text-indigo-200/80 leading-relaxed">
                <span className="font-black text-indigo-400 uppercase mr-2">Re-Mager Protocol:</span> 
                Lawan rasa mager, raih mimpimu! 🔥
              </p>
            </div>
            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-indigo-600 hover:bg-indigo-500 py-5 rounded-3xl font-black text-white shadow-2xl shadow-indigo-900/50 transition-all uppercase tracking-widest"
            >
              Update Protocol
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
          <div className="lg:col-span-2 space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
               <TimerComponent onComplete={handleTimerComplete} onStatusChange={handleTimerStatus} />
               <div className="space-y-6">
                 <CalendarView tasks={state.tasks} />
                 <div className="p-8 glass rounded-3xl border border-white/5 bg-gradient-to-br from-indigo-500/5 to-transparent">
                  <div className="flex justify-between items-end mb-4">
                    <div>
                      <h4 className="font-bold text-xs text-slate-500 uppercase tracking-widest">Total Progress</h4>
                      <p className="text-4xl font-black tracking-tighter">
                        {state.tasks.length > 0 ? Math.round((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100) : 0}%
                      </p>
                    </div>
                    <p className="text-[10px] text-slate-500 font-bold mb-2 uppercase">
                      {state.tasks.filter(t => t.isCompleted).length} / {state.tasks.length} MISSION CLEARED
                    </p>
                  </div>
                  <div className="w-full h-4 bg-slate-900/50 rounded-full overflow-hidden p-1 shadow-inner">
                    <div 
                      className="h-full bg-gradient-to-r from-indigo-600 via-indigo-400 to-cyan-400 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(99,102,241,0.6)]" 
                      style={{ width: `${state.tasks.length > 0 ? Math.min((state.tasks.filter(t => t.isCompleted).length / state.tasks.length) * 100, 100) : 0}%` }}
                    ></div>
                  </div>
                </div>
               </div>
            </div>

            <div className="lg:hidden" onClick={(e) => e.stopPropagation()}>
               <TaskList 
                tasks={state.tasks} 
                onAddTask={addTask} 
                onToggleTask={toggleTask} 
                onDeleteTask={deleteTask} 
              />
            </div>
          </div>

          <div className="hidden lg:block sticky top-28" onClick={(e) => e.stopPropagation()}>
            <TaskList 
              tasks={state.tasks} 
              onAddTask={addTask} 
              onToggleTask={toggleTask} 
              onDeleteTask={deleteTask} 
            />
          </div>
        </div>
      </main>

      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        @keyframes pulse-intense {
          0% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
          50% { transform: scale(1.1); background-color: rgba(249, 115, 22, 0.6); }
          100% { transform: scale(1); background-color: rgba(239, 68, 68, 0.4); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-4px); }
          20%, 40%, 60%, 80% { transform: translateX(4px); }
        }
        @keyframes screen-shake-persistent-anim {
          0%, 100% { transform: translate(0, 0) rotate(0); }
          20% { transform: translate(-10px, 10px) rotate(-2deg); }
          40% { transform: translate(-10px, -10px) rotate(2deg); }
          60% { transform: translate(10px, 10px) rotate(-2deg); }
          80% { transform: translate(10px, -10px) rotate(2deg); }
        }
        .screen-shake-persistent {
          animation: screen-shake-persistent-anim 0.08s infinite;
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 0.8s ease-in-out infinite;
        }
        .animate-pulse-intense {
          animation: pulse-intense 0.8s ease-in-out infinite;
        }
        .animate-shake {
          animation: shake 0.6s cubic-bezier(.36,.07,.19,.97) both;
          animation-iteration-count: 1.5;
        }
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
        input[type="date"]::-webkit-calendar-picker-indicator {
          filter: invert(1);
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task } from '../types';

interface CalendarViewProps {
  tasks: Task[];
}

export const CalendarView: React.FC<CalendarViewProps> = ({ tasks }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  const getDaysInMonth = (year: number, month: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const currentYear = viewDate.getFullYear();
  const currentMonth = viewDate.getMonth();
  const daysInMonth = getDaysInMonth(currentYear, currentMonth);
  const firstDayOfMonth = new Date(currentYear, currentMonth, 1).getDay();

  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const emptyDays = Array.from({ length: firstDayOfMonth }, (_, i) => i);

  const monthName = viewDate.toLocaleString('id-ID', { month: 'long' });

  const tasksByDate = tasks.reduce((acc, task) => {
    const date = task.dueDate;
    if (!acc[date]) acc[date] = [];
    acc[date].push(task);
    return acc;
  }, {} as Record<string, Task[]>);

  const changeMonth = (delta: number) => {
    const newDate = new Date(viewDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setViewDate(newDate);
  };

  const todayStr = new Date().toISOString().split('T')[0];

  const handleDayClick = (dateStr: string) => {
    setSelectedDate(dateStr);
  };

  return (
    <div className="glass p-6 rounded-3xl border border-white/5 space-y-4 relative">
      <div className="flex items-center justify-between mb-2">
        <h3 className="font-black text-xl uppercase tracking-tighter">Mission Schedule</h3>
        <div className="flex gap-2">
          <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7"/></svg>
          </button>
          <span className="font-bold min-w-[120px] text-center text-sm">{monthName} {currentYear}</span>
          <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7"/></svg>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-1">
        {['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'].map(day => (
          <div key={day} className="text-center text-[10px] font-black text-slate-500 uppercase py-2">{day}</div>
        ))}
        {emptyDays.map(d => <div key={`empty-${d}`} className="aspect-square"></div>)}
        {days.map(day => {
          const dateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
          const dayTasks = tasksByDate[dateStr] || [];
          const isToday = dateStr === todayStr;
          const isOverdue = dayTasks.some(t => !t.isCompleted && dateStr < todayStr);

          return (
            <button 
              key={day} 
              onClick={() => handleDayClick(dateStr)}
              className={`aspect-square relative flex flex-col items-center justify-center rounded-xl border transition-all hover:bg-white/10 group 
                ${isToday ? 'bg-indigo-500/20 border-indigo-500/40' : 'border-white/5'}
                ${isOverdue ? 'border-red-500/50 shadow-[inset_0_0_10px_rgba(239,68,68,0.1)]' : ''}
              `}
            >
              <span className={`text-xs font-bold 
                ${isToday ? 'text-indigo-400' : isOverdue ? 'text-red-400' : 'text-slate-400'}
              `}>
                {day}
              </span>
              {dayTasks.length > 0 && (
                <div className="flex gap-0.5 mt-1">
                  {dayTasks.slice(0, 3).map((t) => (
                    <div 
                      key={t.id} 
                      className={`w-1.5 h-1.5 rounded-full ${t.isCompleted ? 'bg-slate-600' : (dateStr < todayStr ? 'bg-red-500' : 'bg-indigo-500 shadow-[0_0_5px_rgba(99,102,241,0.5)] animate-pulse')}`}
                    />
                  ))}
                  {dayTasks.length > 3 && <div className={`text-[8px] font-bold ${isOverdue ? 'text-red-400' : 'text-indigo-400'}`}>+</div>}
                </div>
              )}
            </button>
          );
        })}
      </div>

      {selectedDate && (
        <div className="fixed inset-0 z-[900] flex items-center justify-center p-4 sm:p-6 bg-slate-950/80 backdrop-blur-md animate-in fade-in duration-200" onClick={() => setSelectedDate(null)}>
          <div className="w-full max-w-md bg-slate-900 rounded-[2.5rem] border border-white/10 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200" onClick={(e) => e.stopPropagation()}>
            <div className="p-6 border-b border-white/5 flex items-center justify-between bg-gradient-to-r from-indigo-600/10 to-transparent">
              <div>
                <h4 className="text-xl font-black uppercase tracking-tighter">Mission Control</h4>
                <p className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{new Date(selectedDate).toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</p>
              </div>
              <button 
                onClick={() => setSelectedDate(null)}
                className="p-2 hover:bg-white/5 rounded-xl transition-all text-slate-400 hover:text-white"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="p-6 max-h-[50vh] overflow-y-auto space-y-4 no-scrollbar">
              {tasksByDate[selectedDate] && tasksByDate[selectedDate].length > 0 ? (
                tasksByDate[selectedDate].map(task => {
                    const isTaskOverdue = !task.isCompleted && selectedDate < todayStr;
                    return (
                        <div key={task.id} className={`p-4 rounded-2xl border transition-all ${task.isCompleted ? 'bg-slate-800/30 border-white/5 opacity-50' : (isTaskOverdue ? 'bg-red-950/20 border-red-500/30' : 'bg-slate-800/60 border-indigo-500/20')}`}>
                            <div className="flex items-center justify-between mb-2">
                                <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-md ${isTaskOverdue ? 'bg-red-500 text-white' : 'bg-indigo-500 text-white'}`}>{task.category}</span>
                                {task.reminderTime && <span className={`text-[10px] font-bold ${isTaskOverdue ? 'text-red-400' : 'text-orange-400'}`}>⏰ {task.reminderTime}</span>}
                            </div>
                            <h5 className={`font-bold text-lg leading-tight ${task.isCompleted ? 'line-through text-slate-500' : 'text-white'}`}>{task.title}</h5>
                            <div className="mt-3 flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <div className={`w-2 h-2 rounded-full ${task.isCompleted ? 'bg-slate-500' : (isTaskOverdue ? 'bg-red-500 animate-pulse' : 'bg-green-500 animate-pulse')}`}></div>
                                    <span className={`text-[9px] font-black uppercase ${task.isCompleted ? 'text-slate-500' : (isTaskOverdue ? 'text-red-400' : 'text-green-500')}`}>
                                        {task.isCompleted ? 'Completed' : (isTaskOverdue ? 'OVERDUE' : 'ACTIVE')}
                                    </span>
                                </div>
                                {isTaskOverdue && <span className="text-[8px] font-bold text-red-500 uppercase tracking-widest animate-pulse">STOP MAGER!</span>}
                            </div>
                        </div>
                    );
                })
              ) : (
                <div className="text-center py-12">
                  <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 border border-white/5">
                    <svg className="w-8 h-8 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <p className="text-slate-500 font-bold">Jadwal kosong. Ayo tambahkan misi!</p>
                </div>
              )}
            </div>

            <div className="p-6 bg-slate-900/50 border-t border-white/5">
              <button 
                onClick={() => setSelectedDate(null)}
                className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-black text-white transition-all uppercase tracking-widest text-sm shadow-xl shadow-indigo-900/40"
              >
                Kembali
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
